     if not self.move_piece(from_pos, to_pos) and not self.capture_piece(from_pos, to_pos):\n                print('Invalid move. Please try again.')\n                continue\n\n            if self.check_winner():\n                self.print_board()\n                print(f'Player {self.current_player} wins!')\n                break\n\n            self.switch_player()\n\n    def check_winner(self):\n        # Check if there are any pieces left for the current player\n        count = np.sum(self.board == self.current_player)\n        if count == 0:\n            return True\n        return False"
